import{_ as e,c as d,a,o as r}from"./app-CEcM0piI.js";const s={};function i(h,t){return r(),d("div",null,t[0]||(t[0]=[a('<p>Redis是一个key-value的数据库，key一般是String类型，不过value的类型多种多样：</p><h1 id="通用命令" tabindex="-1"><a class="header-anchor" href="#通用命令"><span>通用命令</span></a></h1><h4 id="keys" tabindex="-1"><a class="header-anchor" href="#keys"><span>keys</span></a></h4><p>查看符合模板的所有key,可以使用通配符*</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>keys *name*    //查看含有name的所有键</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="del" tabindex="-1"><a class="header-anchor" href="#del"><span>del</span></a></h4><p>删除指定的key 可以删除多个,用空格隔开</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>del key1 key2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="exists" tabindex="-1"><a class="header-anchor" href="#exists"><span>exists</span></a></h4><p>判断key是否存在</p><h4 id="expire" tabindex="-1"><a class="header-anchor" href="#expire"><span>expire</span></a></h4><p>给key设置一个有效期,有效期到期自动删除 给age设置20秒的有效期</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>expire age 20</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h4 id="ttl" tabindex="-1"><a class="header-anchor" href="#ttl"><span>ttl</span></a></h4><p>查看key的剩余有效期,如果是-1则永久有效</p><h1 id="key的层级结构" tabindex="-1"><a class="header-anchor" href="#key的层级结构"><span>key的层级结构</span></a></h1><p>Redis的key允许有多个单词形成层级结构，多个单词之间用：隔开，格式如下：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>项目名:业务名:类型:id</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>这个格式并非固定，也可以根据自己的需求来删除或添加词条。</p><h1 id="数据类型" tabindex="-1"><a class="header-anchor" href="#数据类型"><span>数据类型</span></a></h1><p>基本类型</p><table><thead><tr><th>类型</th><th>示例</th></tr></thead><tbody><tr><td>string</td><td>hello world</td></tr><tr><td>Hash</td><td><code>{name:&quot;Jack&quot;,age: 21}</code></td></tr><tr><td>List</td><td>[A -&gt; B -&gt; C -&gt; C]</td></tr><tr><td>Set</td><td><code>{A, B, C}</code></td></tr><tr><td>Sortedset</td><td><code>{A: 1, B: 2, C: 3}</code></td></tr><tr><td>特殊类型</td><td></td></tr></tbody></table><table><thead><tr><th>类型</th><th>示例</th></tr></thead><tbody><tr><td>GEO</td><td><code>{A:(120.3,30.5)}</code></td></tr><tr><td>BitMap</td><td>0110110101110101011</td></tr><tr><td>HyperLog</td><td>0110110101110101011</td></tr></tbody></table><h2 id="string类型" tabindex="-1"><a class="header-anchor" href="#string类型"><span>String类型</span></a></h2><p>根据字符串的格式不同，又可以分为3类：</p><ol><li>string：普通字符串</li><li>int：整数类型，可以做自增、自减操作</li><li>float：浮点类型，可以做自增、自减操作 不管是哪种格式，底层都是字节数组形式存储，只不过是编码方式不同。字符串类型的最大空间不能超过512m.</li></ol><p>常见命令</p><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>SET</td><td>添加或者修改已经存在的一个String类型的键值对</td></tr><tr><td>GET</td><td>根据key获取String类型的value</td></tr><tr><td>MSET</td><td>批量添加多个String类型的键值对</td></tr><tr><td>MGET</td><td>根据多个key获取条个String类型的value</td></tr><tr><td>INCR</td><td>让一个整型的key自增1</td></tr><tr><td>INCRBY</td><td>让一个整型的key自增并指定步长，例如：incrbynum2让num值自增2</td></tr><tr><td>INCRBYFLOAT</td><td>让一个浮点类型的数字自增并指定步长</td></tr><tr><td>SETNX</td><td>添加一个String类型的键值对，前提是这个key不存在，否则不执行</td></tr><tr><td>SETEX</td><td>添加一个String类型的键值对，并且指定有效期</td></tr></tbody></table><h2 id="hash类型" tabindex="-1"><a class="header-anchor" href="#hash类型"><span>Hash类型</span></a></h2><p>Hash类型，也叫散列，其value是一个无序字典，类似于Java中的HashMap结构。</p><p>Hash的存储结构示例</p><table><thead><tr><th>key</th><th>value</th></tr></thead><tbody><tr><td>heima:user:1</td><td>field1:value1 field2:value2...</td></tr></tbody></table><p>常见命令</p><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>HSET key field value</td><td>添加或者修改hash类型key的field的值</td></tr><tr><td>HGET key field</td><td>获取一个hash类型key的field的值</td></tr><tr><td>HMSET</td><td>批量添加多个hash类型key的field的值</td></tr><tr><td>HMGET</td><td>批量获取多个hash类型key的field的值</td></tr><tr><td>HGETALL</td><td>获取一个hash类型的key中的所有的field和value</td></tr><tr><td>HKEYS</td><td>获取一个hash类型的key中的所有的field</td></tr><tr><td>HVALS</td><td>获取一个hash类型的key中的所有的value</td></tr><tr><td>HINCRBY</td><td>让一个hash类型key的字段值自增并指定步长</td></tr><tr><td>HSETNX</td><td>添加一个hash类型的key的field值，前提是这个field不存在，否则不执行<br></td></tr></tbody></table><h2 id="list类型" tabindex="-1"><a class="header-anchor" href="#list类型"><span>List类型</span></a></h2><p>Redis中的List类型与Java中的LinkedList类似，可以看做是一个双向链表结构。既可以支持正向检索和也可以支持反向检索。</p><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>LPUSH key element...</td><td>向列表左侧插入一个或多个元素</td></tr><tr><td>LPOP key</td><td>移除并返回列表左侧的第一个元素，没有则返回nil</td></tr><tr><td>RPUSH key element...</td><td>列表右侧插入一个或多个元素</td></tr><tr><td>RPOP key</td><td>移除并返回列表右侧的第一个元素</td></tr><tr><td>LRANGE key star end</td><td>返回一段索引范围内的所有元素</td></tr><tr><td>BLPOP和BRPOP</td><td>与LPOP和RPOP类似，只不过在没有元素时等待指定时间，而不是直接返回nil</td></tr></tbody></table><h2 id="set类型" tabindex="-1"><a class="header-anchor" href="#set类型"><span>set类型</span></a></h2><p>Redis的Set结构与Java中的HashSet类似，可以看做是一个value为null的HashMap。因为也是一个hash表，因此具备与HashSet类似的特征</p><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>SADD key member...</td><td>向set中添加一个或多个元素</td></tr><tr><td>SREM key member...</td><td>移除set中的指定元素</td></tr><tr><td>SCARD key</td><td>返回set中元素的个数</td></tr><tr><td>SISMEMBER key member</td><td>判断一个元素是否存在于set中</td></tr><tr><td>SMEMBERS</td><td>获取set中的所有元素</td></tr><tr><td>SINTER key1 key2...</td><td>求key1与key2的交集</td></tr><tr><td>SDIFF key key2 ...</td><td>求key1与key2的差集</td></tr><tr><td>SUNION key1 key2 ...</td><td>求key1和key2的并集<br></td></tr></tbody></table><h2 id="sortedset类型" tabindex="-1"><a class="header-anchor" href="#sortedset类型"><span>SortedSet类型</span></a></h2><p>Redis的SortedSet是一个可排序的set集合，与Java中的TreeSet有些类似，但底层数据结构却差别很大。SortedSet中的每一个元素都带有一个score属性，可以基于score属性对元素排序，底层的实现是一个跳表（SkipList）加hash表。</p><table><thead><tr><th>命令</th><th>说明</th></tr></thead><tbody><tr><td>ZADD key score member</td><td>添加一个或多个元素到sorted set，如果已经存在则更新其score值</td></tr><tr><td>ZREM key member</td><td>删除sorted set中的一个指定元素</td></tr><tr><td>ZSCORE key member</td><td>获取sortedset中的指定元素的score值</td></tr><tr><td>ZRANK key member</td><td>获取sortedset中的指定元素的排名</td></tr><tr><td>ZCARD key</td><td>获取sorted set中的元素个数</td></tr><tr><td>ZCOUNT key min max</td><td>统计score值在给定范围内的所有元素的个数</td></tr><tr><td>ZINCRBY key increment member</td><td>让sorted set中的指定元素自增，步长为指定的increment值</td></tr><tr><td>ZRANGE key min max</td><td>按照score排序后，获取指定排名范围内的元素</td></tr><tr><td>ZRANGEBYSCORE key min max</td><td>按照score排序后，获取指定score范围内的元素</td></tr><tr><td>ZDIFF、ZINTER、ZUNION</td><td>求差集、交集、并集</td></tr></tbody></table><p>所有的排名默认都是升序，如果要降序则在命令的Z后面添加REV即可</p>',44)]))}const l=e(s,[["render",i]]),p=JSON.parse('{"path":"/tools/redis/1/","title":"1 概述","lang":"zh-CN","frontmatter":{"title":"1 概述","createTime":"2025/04/05 12:12:26","permalink":"/tools/redis/1/"},"readingTime":{"minutes":4.57,"words":1372},"git":{"createdTime":1750599657000,"updatedTime":1750644294000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":2,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/工具/Redis/1 概述.md","headers":[]}');export{l as comp,p as data};
